defmodule MyApp.Accounts.User do
  use Ecto.Schema
  import Ecto.Changeset

  @primary_key {:id, :binary_id, autogenerate: true}
  @foreign_key_type :binary_id
  
  schema "users" do
    field :email, :string
    field :name, :string
    field :password, :string, virtual: true
    field :password_hash, :string
    field :role, :string
    field :status, :string
    field :phone, :string
    field :address, :string
    field :bio, :string
    field :avatar_url, :string
    field :preferences, :map
    field :metadata, :map

    timestamps()
  end

  @allowed_fields [
    :email,
    :name,
    :password,
    :role,
    :status,
    :phone,
    :address,
    :bio,
    :avatar_url,
    :preferences,
    :metadata
  ]

  @required_fields [:email, :name]

  def changeset(user, attrs) do
    user
    |> cast(attrs, @allowed_fields)
    |> validate_required(@required_fields)
    |> validate_email()
    |> validate_password()
    |> validate_role()
    |> validate_status()
    |> validate_length(:name, min: 2, max: 100)
    |> validate_length(:phone, max: 20)
    |> validate_length(:bio, max: 500)
    |> unique_constraint(:email)
    |> hash_password()
  end

  defp validate_email(changeset) do
    changeset
    |> validate_format(:email, ~r/^[^\s]+@[^\s]+\.[^\s]+$/, message: "must be a valid email")
    |> validate_length(:email, max: 160)
    |> update_change(:email, &String.downcase/1)
  end

  defp validate_password(changeset) do
    changeset
    |> validate_length(:password, min: 8, max: 128)
    |> validate_format(:password, ~r/[a-z]/, message: "must contain at least one lowercase letter")
    |> validate_format(:password, ~r/[A-Z]/, message: "must contain at least one uppercase letter")
    |> validate_format(:password, ~r/[0-9]/, message: "must contain at least one digit")
    |> validate_format(:password, ~r/[!@#$%^&*(),.?":{}|<>]/, message: "must contain at least one special character")
  end

  defp validate_role(changeset) do
    validate_inclusion(changeset, :role, ["admin", "user", "moderator", "guest"], message: "invalid role")
  end

  defp validate_status(changeset) do
    validate_inclusion(changeset, :status, ["active", "inactive", "suspended", "pending"], message: "invalid status")
  end

  defp hash_password(changeset) do
    case get_change(changeset, :password) do
      nil ->
        changeset
      password ->
        changeset
        |> put_change(:password_hash, Bcrypt.hash_pwd_salt(password))
        |> delete_change(:password)
    end
  end
end

defmodule MyAppWeb.FallbackController do
  use MyAppWeb, :controller

  def call(conn, {:error, %Ecto.Changeset{} = changeset}) do
    conn
    |> put_status(:unprocessable_entity)
    |> put_view(MyAppWeb.ChangesetView)
    |> render("error.json", changeset: changeset)
  end

  def call(conn, {:error, :not_found}) do
    conn
    |> put_status(:not_found)
    |> put_view(MyAppWeb.ErrorView)
    |> render(:"404")
  end
end

